import React from 'react';
import { Link } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, List, Home } from 'lucide-react';

const Sidebar = () => {
  const linkStyle = {
    display: 'flex', alignItems: 'center', gap: '10px', 
    textDecoration: 'none', color: '#333', marginBottom: '20px'
  };

  return (
    <div style={{ width: '250px', height: '100vh', background: '#f4f4f4', padding: '20px', borderRight: '1px solid #ddd' }}>
      <h3>Finanças App</h3>
      <nav style={{ marginTop: '40px' }}>
        <Link to="/" style={linkStyle}><Home size={20} /> Início</Link>
        <Link to="/lancamento" style={linkStyle}><PlusCircle size={20} /> Novo Lançamento</Link>
        <Link to="/listagem" style={linkStyle}><List size={20} /> Minhas Despesas</Link>
        <Link to="/dashboard" style={linkStyle}><LayoutDashboard size={20} /> Dashboard</Link>
      </nav>
    </div>
  );
};

export default Sidebar;
